{{-- ── Health-check toast ───────────────────────────────────────────── --}}
<div id="health-toast" style="display:none;position:fixed;bottom:24px;right:24px;z-index:9999;color:#fff;border-radius:10px;padding:12px 20px;font-family:'Inter',sans-serif;font-size:13.5px;box-shadow:0 4px 24px rgba(0,0,0,0.18);align-items:center;gap:10px;"></div>

<script>
function checkHealth(platform, btn) {
    const orig = btn.innerHTML;
    btn.disabled = true;
    btn.innerHTML = '<svg class="spin" width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><polyline points="23 4 23 10 17 10"/><path d="M20.49 15a9 9 0 11-2.12-9.36L23 10"/></svg> Checking…';

    fetch(`/marketing/integrations/${platform}/health-check`, {
        method: 'POST',
        headers: {
            'X-CSRF-TOKEN': '{{ csrf_token() }}',
            'Accept': 'application/json',
        }
    })
    .then(r => r.json())
    .then(data => {
        showToast(data.status === 'connected' ? '✓ Connection is healthy' : '' + (data.message || 'Connection error'), data.status === 'connected');
        if (data.status !== 'connected') setTimeout(() => location.reload(), 1800);
    })
    .catch(() => showToast('Could not reach server', false))
    .finally(() => { btn.disabled = false; btn.innerHTML = orig; });
}

function showToast(msg, ok) {
    const t = document.getElementById('health-toast');
    t.textContent    = msg;
    t.style.background = ok ? '#166534' : '#991b1b';
    t.style.display    = 'flex';
    setTimeout(() => t.style.display = 'none', 3000);
}
</script>

<style>
@keyframes spin { to { transform: rotate(360deg); } }
.spin { animation: spin 0.8s linear infinite; }
